  display_name   = "observability-networking-135"

  # Configuracao especifica
  shape          = "VM.Standard.E4.Flex"

  tags = {
    project     = "AutoDrive Systems - container-platform"
    environment = "networking"
    managed_by  = "terraform"
  }
}

variable "compartment_ocid" {
  type        = string
  description = "OCID do compartment networking"
}

output "resource_id" {
  value = oci_monitoring_alarm.main.id
}
```

**variables.tf:**
```hcl
variable "compartment_ocid" {
  type        = string
  description = "OCID do compartment"
}

variable "region" {
  type        = string
  default     = "ap-mumbai-1"
  description = "Regiao OCI"
}
```

**Deploy:**
```bash
terraform init
terraform plan -var="compartment_ocid=ocid1.cluster.eu.0c565c485bd3499022be7cc9825adcb9"
terraform apply -var="compartment_ocid=ocid1.cluster.eu.0c565c485bd3499022be7cc9825adcb9" -auto-approve
```

**Configuracao:**
- Compartment: `networking`
- Region: `ap-mumbai-1`
- Shape: `VM.Standard.E4.Flex`
